// ============================================================
// myQRID Logo System — logo.js
// Source: Verified_Final_Master_Logo.svg (FROZEN MASTER)
//         sticker-type4-qr-A7GH9-v2_2.svg (FROZEN MASTER)
// 
// RULES:
// Dark bg  → MYQRID_LOGO_DARK  (white ring+text, gradient Q)
// Light bg → MYQRID_LOGO_LIGHT (black ring+text, gradient Q)
// App icon → MYQRID_ICON       (gradient Q only, no ring/text)
// QR dark  → MYQRID_QR_DARK   (white QR+ring+text)
// QR light → MYQRID_QR_LIGHT  (black QR+ring+text)
//
// DO NOT regenerate from scratch — always derive from frozen masters
// ============================================================

// Full circle logo — dark backgrounds (white ring+text + gradient Q)
const MYQRID_LOGO_DARK = "data:image/svg+xml;base64,";

// Full circle logo — light backgrounds (black ring+text + gradient Q)
const MYQRID_LOGO_LIGHT = "data:image/svg+xml;base64,";

// App icon — gradient Q only (no ring, no text) — for favicon, PWA, home screen
const MYQRID_ICON = "data:image/svg+xml;base64,";

// QR sticker — dark backgrounds (all white)
const MYQRID_QR_DARK = "data:image/svg+xml;base64,";

// QR sticker — light backgrounds (all black)
const MYQRID_QR_LIGHT = "data:image/svg+xml;base64,";

// PNG master — for browsers that need PNG (email, meta tags)
const MYQRID_PNG = "data:image/png;base64,";

// Default export (dark bg assumed — coffee/purple are default app themes)
const MYQRID_LOGO = MYQRID_LOGO_DARK;

// ── Usage Guide ──────────────────────────────────────────────
// Navbar top bar (dark bg):         MYQRID_LOGO_DARK   28-32px
// Splash/hero (dark bg):            MYQRID_LOGO_DARK   80-120px
// Login/Signup page:                MYQRID_LOGO_DARK   72px
// Bottom nav center button:         MYQRID_ICON        28-32px
// PWA icon / Add to Home Screen:    MYQRID_ICON        (SVG scales)
// Favicon:                          MYQRID_ICON
// Profile QR code display:          MYQRID_QR_DARK     (full sticker)
// Light bg contexts (print/email):  MYQRID_LOGO_LIGHT
// ─────────────────────────────────────────────────────────────

// Auto-inject into elements
function injectLogos() {
  // Full logo into navbar/splash images
  document.querySelectorAll(
    'img[id*="logo"], img[id*="Logo"], img[id*="splash"]'
  ).forEach(el => {
    if (!el.src || el.src === window.location.href || el.src.endsWith('/')) {
      el.src = MYQRID_LOGO_DARK;
      el.alt = el.alt || 'myQRID';
    }
  });

  // Icon-only for nav center btn, favicon targets
  document.querySelectorAll(
    'img[data-logo="icon"], img[id*="nav-logo"], img[id*="navlogo"]'
  ).forEach(el => {
    el.src = MYQRID_ICON;
    el.alt = el.alt || 'myQRID';
  });

  // QR displays
  document.querySelectorAll('img[data-logo="qr"]').forEach(el => {
    el.src = MYQRID_QR_DARK;
    el.alt = el.alt || 'myQRID QR';
  });

  // Dynamic favicon
  const favicon = document.querySelector('link[rel*="icon"]');
  if (favicon) favicon.href = MYQRID_ICON;
}

document.addEventListener('DOMContentLoaded', injectLogos);
